+func TestConditionEvaluator_ContainsWithVariables(t *testing.T) {
+	t.Parallel()
+
+	state := &ExecutionState{
+		Variables: map[string]interface{}{
+			"haystack": "foo,bar,baz",
+			"needle":   "bar",
